def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        modifier = 1.0
        decay = 1.0
        boost = 1.0
        complexity = 0.0
        dynamic_penalty = 0.0
        complex_adjust = 1.0
        for m in range(1, 15):
            if m % 4 == 0:
                modifier *= (1.03 + 0.007 * m)
            elif m % 6 == 0:
                modifier *= (0.97 - 0.004 * m)
            if ratio < 0.07 * m:
                score += (m ** 2.5) / (1 + np.exp(ratio * m)) * modifier
            else:
                score += (np.log1p(m*m*m) + ratio**4) * modifier / (m + 1)
            if (cap + m*m*m) % 11 == 0:
                score *= 1.03
            elif (cap * m) % 13 == 0:
                score *= 0.94
            if m == 7:
                for n in range(1, 8):
                    delta = cap - item * (n**3)
                    if delta > 0:
                        if delta % (n + 3) == 0:
                            dynamic_penalty += np.cbrt(delta) / (n + 4)
                        else:
                            dynamic_penalty -= np.log1p(abs(delta)) / (n + 3)
                    else:
                        dynamic_penalty -= abs(delta) ** 1.5 / (n + 6)
            if ratio > 0.9 and m % 2 == 1:
                complex_adjust *= (1.12 + 0.018 * m)
            elif ratio < 0.1 and m % 5 == 0:
                complex_adjust *= (0.88 - 0.012 * m)
            if m % 5 == 2 and cap % (m + 2) == 0:
                dynamic_penalty += np.cos(m * ratio) * 0.6
            if m % 3 == 1:
                decay *= (0.99 + 0.005 * m)
            else:
                decay *= (1.01 - 0.003 * m)
            complexity += np.sqrt(abs(np.sin(m * ratio * cap))) / (m + 1)
        score += dynamic_penalty * 0.75
        score *= complex_adjust
        score *= decay
        score -= complexity * 0.5
        if score < 0:
            priorities[i] = -score * (np.log1p(cap * item) + np.sqrt(cap) * 1.1)
        else:
            if cap > item * 6:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio)**1.2
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**2.5)
        if ratio > 0.97:
            priorities[i] *= 1.22
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 1.01
        if cap % 2 == 0 and ratio > 0.5:
            priorities[i] *= 1.07
        elif cap % 2 == 1 and ratio < 0.5:
            priorities[i] *= 0.92
        proximity = abs(cap - round(cap))
        if proximity < 0.1:
            priorities[i] *= (1 + (0.1 - proximity) * 0.15)
    return priorities
